<script lang="ts">import{onMount}from'svelte';import{loadScores,fmt,type ScoreData}from'$lib/scores';let data=$state<ScoreData|null>(null),weights=$state<Record<number,number>>({}),normalize=$state(true),name=$state('My perspective');onMount(async()=>{const d=await loadScores();data=d;weights=Object.fromEntries(d.categories.map(c=>[c.id,20]));await recalc()});let total=$derived(Object.values(weights).reduce((a,b)=>a+b,0));async function recalc(){if(!data)return;const effective=normalize&&total?Object.fromEntries(Object.entries(weights).map(([k,v])=>[Number(k),v/total])):Object.fromEntries(Object.entries(weights).map(([k,v])=>[Number(k),v/100]));data=await loadScores(effective)}function change(id:number,value:number){weights={...weights,[id]:Math.max(0,Math.min(100,value))};void recalc()}function reset(){if(!data)return;weights=Object.fromEntries(data.categories.map(c=>[c.id,20]));void recalc()}function save(){localStorage.setItem('statescore-profile',JSON.stringify({name,weights}));alert('Perspective saved on this device.')}</script>
<svelte:head><title>Your priorities · StateScore</title></svelte:head><div class="page-head"><div><p class="eyebrow">Scoring perspective</p><h1>Your priorities</h1><p>Weights describe what matters to you. They do not make one state objectively “best.” Ranking changes appear immediately.</p></div></div>{#if data}<section class="workspace"><div class="card editor"><div class="profile"><div class="field"><label for="name">Perspective name</label><input id="name" bind:value={name}/></div><label class="check"><input type="checkbox" bind:checked={normalize} onchange={recalc}/> Automatically normalize to 100%</label></div>{#each data.categories as c,i}<div class="weight"><span class={`swatch c${i}`}></span><label for={`w${c.id}`}><strong>{c.name}</strong><small>{c.description}</small></label><input id={`w${c.id}`} type="range" min="0" max="100" value={weights[c.id]} oninput={(e)=>change(c.id,+(e.currentTarget as HTMLInputElement).value)}/><div class="number"><input aria-label={`${c.name} weight`} type="number" min="0" max="100" value={weights[c.id]} oninput={(e)=>change(c.id,+(e.currentTarget as HTMLInputElement).value)}/><span>%</span></div></div>{/each}<footer><strong class:bad={!normalize&&total!==100}>{total}% {normalize?'entered':'total'}</strong><div><button class="btn secondary" onclick={reset}>Reset</button><button class="btn" onclick={save} disabled={!normalize&&total!==100}>Save perspective</button></div></footer></div><aside class="card preview"><p class="eyebrow">Live ranking</p><h2>What changes</h2>{#each data.rows.slice(0,8) as row,i}<a href={`/states/${row.state.code}`}><b>{i+1}</b><span>{row.state.name}</span><em class="score">{fmt(row.overall)}</em></a>{/each}<p class="muted">Scores update using the same category results; only their contribution to the overall score changes.</p></aside></section>{/if}
<style>.workspace{display:grid;grid-template-columns:minmax(0,1.5fr) minmax(260px,.7fr);gap:1rem}.profile{display:flex;justify-content:space-between;align-items:end;padding-bottom:1.5rem}.check{display:flex;gap:.4rem}.weight{display:grid;grid-template-columns:8px minmax(150px,1fr) 1.3fr 90px;gap:1rem;align-items:center;padding:1rem 0;border-top:1px solid var(--mist)}.weight label small{display:block;color:var(--muted)}.swatch{height:44px;border-radius:5px;background:var(--lake)}.swatch.c1{background:#4c75a3}.swatch.c2{background:#55a67a}.swatch.c3{background:#d89045}.swatch.c4{background:var(--coral)}input[type=range]{accent-color:var(--lake)}.number{display:flex;align-items:center}.number input{width:65px;font-family:var(--font-data)}footer{display:flex;justify-content:space-between;align-items:center;padding-top:1.5rem;border-top:2px solid var(--blue)}footer>div{display:flex;gap:.5rem}.bad{color:var(--coral)}.preview{align-self:start;position:sticky;top:2rem}.preview h2{font:400 2rem var(--font-display);margin-top:0}.preview a{display:grid;grid-template-columns:2rem 1fr auto;gap:.5rem;padding:.75rem 0;border-top:1px solid var(--mist);text-decoration:none}.preview a b{color:var(--muted)}.preview a em{font-style:normal}.preview>p:last-child{font-size:.8rem;margin-top:2rem}@media(max-width:900px){.workspace{grid-template-columns:1fr}.preview{position:static}}@media(max-width:650px){.weight{grid-template-columns:8px 1fr 80px}.weight>input[type=range]{grid-column:2/4;width:100%}.profile{align-items:start;flex-direction:column;gap:1rem}}</style>
